import { mkdir, writeFile } from 'node:fs/promises';
import { join, relative } from 'node:path';

const GENERATED_HEADER =
  '// AUTO-GENERATED by @apostrophecms/apostrophe-astro. Do not edit.\n' +
  '// This file is regenerated on every dev server start and build.\n';

/**
 * Write config.js and doctypes.js under
 * `node_modules/.apostrophe-astro-config/`.
 *
 * @param {object} params
 * @param {string} params.projectRoot - Astro project root (config.root).
 * @param {object} params.integrationConfig - Resolved integration config to serialise.
 * @param {string} params.widgetsId  - Resolved absolute path to widgetsMapping module.
 * @param {string} params.templatesId - Resolved absolute path to templatesMapping module.
 * @param {string|null} params.hookId - Resolved absolute path to onBeforeWidgetRender, or null.
 */
async function writeGeneratedRuntimeFiles({
  projectRoot,
  integrationConfig,
  widgetsId,
  templatesId,
  hookId
}) {
  // Write to two locations:
  //
  // 1. node_modules/.apostrophe-astro-config/ — dot-prefixed for Vite
  //    (conventional location for generated Vite artifacts; kept as the
  //    Vite alias target for belt-and-suspenders coverage in all Vite
  //    environments including dev server hot-reload).
  //
  // 2. node_modules/apostrophe-astro-config/ — a real Node-resolvable
  //    package so that `import 'apostrophe-astro-config/config'` works
  //    natively in Node's ESM loader without needing a Vite alias.
  //    This is essential for Astro v6 static builds where the prerender
  //    environment may execute page modules outside Vite's plugin chain.
  const dotDir = join(projectRoot, 'node_modules', '.apostrophe-astro-config');
  const pkgDir = join(projectRoot, 'node_modules', 'apostrophe-astro-config');

  await mkdir(dotDir, { recursive: true });
  await mkdir(pkgDir, { recursive: true });

  // ── package.json (real package only) ──────────────────────────────────────
  const pkgJson = JSON.stringify({
    name: 'apostrophe-astro-config',
    version: '0.0.0',
    type: 'module',
    exports: {
      './config': './config.js',
      './doctypes': './doctypes.js'
    }
  }, null, 2) + '\n';

  await writeFile(join(pkgDir, 'package.json'), pkgJson);

  // ── config.js ──────────────────────────────────────────────────────────────
  // Serialise the resolved integration config as a static ES module export.
  // All keys are always present so consumer code can rely on their shape.
  const configObj = {
    aposHost: integrationConfig.aposHost ?? null,
    aposPrefix: integrationConfig.aposPrefix ?? '',
    includeResponseHeaders: integrationConfig.includeResponseHeaders ?? null,
    excludeRequestHeaders: integrationConfig.excludeRequestHeaders ?? null,
    viewTransitionWorkaround: integrationConfig.viewTransitionWorkaround ?? false,
    staticBuild: integrationConfig.staticBuild ?? null
  };

  const configContent =
    GENERATED_HEADER +
    '\nexport default ' +
    JSON.stringify(configObj, null, 2) +
    ';\n';

  await writeFile(join(dotDir, 'config.js'), configContent);
  await writeFile(join(pkgDir, 'config.js'), configContent);

  // ── doctypes.js ────────────────────────────────────────────────────────────
  // Re-export the user's mapping modules using relative paths from the
  // generated directory so the file is portable across machines and moves.
  // We use the dot-prefixed directory for relative path calculation since
  // both directories are siblings and produce identical relative paths.
  function toRelative(absPath) {
    let rel = relative(dotDir, absPath).replace(/\\/g, '/');
    if (!rel.startsWith('.')) {
      rel = './' + rel;
    }
    return rel;
  }

  let hookImport = '';
  let hookExport = 'undefined';
  if (hookId) {
    hookImport = `import onBeforeWidgetRenderHookFn from ${JSON.stringify(toRelative(hookId))};\n`;
    hookExport = 'onBeforeWidgetRenderHookFn';
  }

  const doctypesContent =
    GENERATED_HEADER +
    '\n' +
    `import { default as widgets } from ${JSON.stringify(toRelative(widgetsId))};\n` +
    `import { default as templates } from ${JSON.stringify(toRelative(templatesId))};\n` +
    hookImport +
    '\nexport { widgets, templates };\n' +
    `export const onBeforeWidgetRenderHook = ${hookExport};\n`;

  await writeFile(join(dotDir, 'doctypes.js'), doctypesContent);
  await writeFile(join(pkgDir, 'doctypes.js'), doctypesContent);
}

/**
 * Extract the resolved ID string from a Vite resolver result.
 * Vite resolvers may return a string or an object with an `id` property.
 *
 * @param {string|{id:string}|null|undefined} result
 * @returns {string|null}
 */
function extractId(result) {
  if (!result) return null;
  if (typeof result === 'string') return result;
  return result.id ?? null;
}

/**
 * Vite plugin that generates real runtime files to replace the two
 * old virtual-module plugins (`vite-plugin-apostrophe-config` and
 * `vite-plugin-apostrophe-doctype`).
 *
 * Files are written to `node_modules/.apostrophe-astro-config/` and
 * consumed through Vite aliases registered by the integration's
 * `astro:config:setup` hook.
 *
 * Timing strategy
 * ───────────────
 * • Dev mode  – `configureServer` returns a post-middleware hook that
 *   runs after Vite's plugin container is fully initialised but before
 *   any request is served, giving us access to `server.pluginContainer`
 *   for resolution.
 * • Build mode – `buildStart` has `this.resolve()` available and runs
 *   before any module transformation begins.
 *
 * A `filesWritten` flag prevents redundant disk writes if both hooks
 * happen to fire in the same process.
 *
 * @param {import('../index.js').ApostropheIntegrationOptions} options
 * @param {object} integrationConfig - Resolved integration config to serialise.
 * @param {string} projectRoot - Astro project root (`config.root`).
 * @returns {import('vite').Plugin}
 */
export function vitePluginApostropheGeneratedConfig(options, integrationConfig, projectRoot) {
  let filesWritten = false;
  const rootImporter = join(projectRoot, 'astro.config.mjs');

  /**
   * Resolve user mapping paths then write the generated files.
   *
   * @param {(id: string) => Promise<string|{id:string}|null>} resolveId
   */
  async function resolveAndWrite(resolveId) {
    const rawWidgets = await resolveId(options.widgetsMapping);
    const widgetsId = extractId(rawWidgets);
    if (!widgetsId) {
      throw new Error(
        `Could not resolve apostrophe-astro widgetsMapping: ${options.widgetsMapping}`
      );
    }

    const rawTemplates = await resolveId(options.templatesMapping);
    const templatesId = extractId(rawTemplates);
    if (!templatesId) {
      throw new Error(
        `Could not resolve apostrophe-astro templatesMapping: ${options.templatesMapping}`
      );
    }

    let hookId = null;
    if (options.onBeforeWidgetRender) {
      const rawHook = await resolveId(options.onBeforeWidgetRender);
      hookId = extractId(rawHook);
      if (!hookId) {
        throw new Error(
          `Could not resolve apostrophe-astro onBeforeWidgetRender: ${options.onBeforeWidgetRender}`
        );
      }
    }

    await writeGeneratedRuntimeFiles({
      projectRoot,
      integrationConfig,
      widgetsId,
      templatesId,
      hookId
    });

    filesWritten = true;
  }

  return {
    name: 'vite-plugin-apostrophe-generated-config',
    enforce: 'pre',

    // ── Dev mode ──────────────────────────────────────────────────────────────
    // The function returned from configureServer runs after all middlewares
    // are installed, before the server begins handling requests.  At that
    // point server.pluginContainer is fully initialised and can resolve IDs.
    configureServer(server) {
      return async () => {
        if (!filesWritten) {
          await resolveAndWrite((id) =>
            server.pluginContainer.resolveId(id, rootImporter, { ssr: true })
          );
        }
      };
    },

    // ── Build mode ────────────────────────────────────────────────────────────
    // buildStart provides this.resolve() and runs before any module is
    // transformed, so the generated files exist when aliases are first hit.
    async buildStart() {
      if (!filesWritten) {
        const self = this;
        await resolveAndWrite((id) => self.resolve(id, rootImporter));
      }
    }
  };
}
